public struct PK_LOGICAL_t
{
    private byte value = 0;
    public byte Value
    {
        get
        {
            return value;
        }

        set
        {
            this.value = value;
        }
    }

    public PK_LOGICAL_t(byte value)
    {
        this.value = value;
    }

    public static implicit operator byte (PK_LOGICAL_t operand)
    {
        return operand.value;
    }

    public static implicit operator PK_LOGICAL_t(byte operand)
    {
        return new PK_LOGICAL_t(operand);
    }

    public static implicit operator bool (PK_LOGICAL_t operand)
    {
        return (operand.value != 0) ? true : false;
    }

    public static implicit operator PK_LOGICAL_t(bool operand)
    {
        return operand ? PK_LOGICAL_true : PK_LOGICAL_false;
    }

    public static implicit operator int (PK_LOGICAL_t operand)
    {
        return (operand.value != 0) ? 1 : 0;
    }

    public static implicit operator PK_LOGICAL_t(int operand)
    {
        return (operand != 0) ? PK_LOGICAL_true : PK_LOGICAL_false;
    }

    public static bool operator ==(PK_LOGICAL_t x, PK_LOGICAL_t y)
    {
        return x.value == y.value;
    }

    public static bool operator !=(PK_LOGICAL_t x, PK_LOGICAL_t y)
    {
        return x.value != y.value;
    }

    public override readonly bool Equals(object? o)
    {
        return o switch
        {
            byte b => this.value == b,
            bool b => (this.value != 0) == b,
            int i => (this.value != 0) == (i != 0),
            _ => false,
        };
    }

    public override readonly int GetHashCode()
    {
        return value;
    }
}
